702	function fmt(n, decimals) {
703	  if (n == null || isNaN(n)) return '--';
704	  decimals = decimals != null ? decimals : 2;
705	  return Number(n).toLocaleString(undefined, { minimumFractionDigits: decimals, maximumFractionDigits: decimals });
706	}
707	
708	function pnlClass(v) {
709	  if (v > 0) return 'positive';
710	  if (v < 0) return 'negative';
711	  return '';
712	}
713	
714	function dirClass(d) {
715	  if (!d) return '';
716	  const u = d.toUpperCase();
717	  if (u === 'BUY' || u === 'LONG') return 'dir-buy';
718	  if (u === 'SELL' || u === 'SHORT') return 'dir-sell';
719	  return 'dir-hold';
720	}
721	
722	function escHtml(s) {
723	  if (s == null) return '';
724	  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
725	}
