727	function humanCloseReason(reason) {
728	  if (!reason) return 'Closed';
729	  const map = {
730	    'STOP_LOSS_ORDER': 'Stop-loss hit (auto-closed to limit loss)',
731	    'TAKE_PROFIT_ORDER': 'Take-profit hit (closed at target)',
732	    'TRAILING_STOP_LOSS_ORDER': 'Trailing stop triggered',
733	    'MARKET_ORDER': 'Closed by bot',
734	  };
735	  // Check for partial matches too (OANDA reasons can vary)
736	  for (const [key, val] of Object.entries(map)) {
737	    if (reason.toUpperCase().includes(key)) return val;
738	  }
739	  return reason;
740	}
