742	function shortTime(ts) {
743	  if (!ts) return '--';
744	  try {
745	    const d = new Date(ts);
746	    return d.toLocaleString(undefined, { month:'short', day:'numeric', hour:'2-digit', minute:'2-digit', second:'2-digit' });
747	  } catch { return ts; }
748	}
