763	/* ── Start / Stop ── */
764	async function toggleInstance() {
765	  const btn = document.getElementById('startStopBtn');
766	  const isRunning = btn.classList.contains('running');
767	  const action = isRunning ? 'stop' : 'start';
768	  if (activeInstance === 'live') {
769	    if (!confirm('This will ' + action + ' live trading with real money. Continue?')) return;
770	  }
771	
772	  // Disable button while processing
773	  btn.disabled = true;
774	  btn.textContent = isRunning ? 'Stopping...' : 'Starting...';
775	
776	  try {
